## Request Validation with Zod

### Schema definition
```ts
// users/users.schema.ts
import { z } from 'zod';

export const createUserSchema = z.object({
  body: z.object({
    email: z.string().email(),
    name:  z.string().min(2).max(100),
    role:  z.enum(['admin', 'user', 'guest']).default('user'),
  }),
});

export const getUserSchema = z.object({
  params: z.object({ id: z.string().uuid() }),
});

export const listUsersSchema = z.object({
  query: z.object({
    page:  z.coerce.number().int().min(1).default(1),
    limit: z.coerce.number().int().min(1).max(100).default(20),
    role:  z.enum(['admin', 'user', 'guest']).optional(),
  }),
});
```

### Validation middleware
```ts
// shared/middleware/validate.ts
import { RequestHandler } from 'express';
import { ZodSchema, ZodError } from 'zod';

export function validate(schema: ZodSchema): RequestHandler {
  return (req, res, next) => {
    const result = schema.safeParse({ body: req.body, query: req.query, params: req.params });
    if (!result.success) {
      const errors = result.error.flatten();
      return res.status(400).json({ error: 'Validation failed', details: errors.fieldErrors });
    }
    // Overwrite with parsed/coerced/defaulted values
    Object.assign(req, result.data);
    next();
  };
}
```

### Usage
```ts
router.post('/users', validate(createUserSchema), createUserController);
router.get('/users/:id', validate(getUserSchema), getUserController);
```

## Centralized Error Handling Middleware

### Custom error classes
```ts
// shared/errors.ts
export class AppError extends Error {
  constructor(public message: string, public statusCode = 500, public code?: string) {
    super(message);
    this.name = 'AppError';
  }
}
export class NotFoundError    extends AppError { constructor(r: string) { super(`${r} not found`, 404, 'NOT_FOUND'); } }
export class ValidationError  extends AppError { constructor(m: string) { super(m, 400, 'VALIDATION_ERROR'); } }
export class UnauthorizedError extends AppError { constructor() { super('Unauthorized', 401, 'UNAUTHORIZED'); } }
export class ForbiddenError   extends AppError { constructor() { super('Forbidden', 403, 'FORBIDDEN'); } }
```

### Error handler middleware
```ts
// Must have 4 params — Express detects error middleware by arity
import { ErrorRequestHandler } from 'express';
import { AppError } from '../errors';
import { ZodError } from 'zod';

export const errorHandler: ErrorRequestHandler = (err, req, res, next) => {
  if (res.headersSent) return next(err);

  if (err instanceof ZodError) {
    return res.status(400).json({ error: 'Validation failed', details: err.flatten().fieldErrors });
  }

  if (err instanceof AppError) {
    return res.status(err.statusCode).json({ error: err.message, code: err.code });
  }

  // Unexpected — log full error, send generic message
  logger.error({ err, url: req.url, method: req.method }, 'Unexpected error');
  res.status(500).json({ error: 'Internal server error' });
};

// Register last in app.ts
app.use(errorHandler);
```

**Rules:**
- Never include `err.stack` in the response body — expose only in logs
- Use async wrappers or `express-async-errors` to catch async rejections automatically

## Graceful Shutdown

```ts
// server.ts
import { createServer } from 'http';
import { app } from './app';
import { db } from './shared/db/client';

const server = createServer(app);
const PORT = process.env.PORT || 3000;

server.listen(PORT, () => console.log(`Listening on ${PORT}`));

async function shutdown(signal: string) {
  console.log(`Received ${signal}. Shutting down gracefully...`);

  // 1. Stop accepting new connections
  server.close(async () => {
    try {
      // 2. Close DB pool
      await db.$disconnect(); // Prisma
      // or: await pool.end(); // pg
      console.log('DB disconnected. Exiting.');
      process.exit(0);
    } catch (err) {
      console.error('Shutdown error:', err);
      process.exit(1);
    }
  });

  // 3. Force exit if drain takes too long
  setTimeout(() => {
    console.error('Graceful shutdown timeout. Forcing exit.');
    process.exit(1);
  }, 30_000);
}

process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT',  () => shutdown('SIGINT'));
process.on('uncaughtException',  err => { logger.fatal(err, 'uncaughtException');  process.exit(1); });
process.on('unhandledRejection', err => { logger.fatal(err, 'unhandledRejection'); process.exit(1); });
```

## Environment Config Validation

```ts
// shared/config.ts
import { z } from 'zod';

const envSchema = z.object({
  NODE_ENV:    z.enum(['development', 'test', 'production']).default('development'),
  PORT:        z.coerce.number().int().min(1024).max(65535).default(3000),
  DATABASE_URL: z.string().url(),
  JWT_SECRET:  z.string().min(32),
  JWT_EXPIRES_IN: z.string().default('7d'),
  CORS_ORIGIN: z.string().url().optional(),
  LOG_LEVEL:   z.enum(['trace', 'debug', 'info', 'warn', 'error']).default('info'),
});

const parsed = envSchema.safeParse(process.env);

if (!parsed.success) {
  console.error('Invalid environment variables:');
  console.error(parsed.error.flatten().fieldErrors);
  process.exit(1);
}

export const config = parsed.data;
// Use: config.DATABASE_URL — fully typed, never undefined
```

**Rules:**
- This module must be imported before any other module that uses env vars
- Never access `process.env.FOO` directly outside this file
- `.env` files are for local dev only — production uses injected environment
- Never commit `.env` — commit `.env.example` with placeholder values

## Rate Limiting

```ts
import rateLimit from 'express-rate-limit';

// Global API limit
export const globalLimit = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 500,
  standardHeaders: 'draft-7',
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});

// Strict limit for auth endpoints
export const authLimit = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 10, // max 10 login attempts per 15 min
  skipSuccessfulRequests: true, // don't count successful logins
  message: { error: 'Too many login attempts. Try again in 15 minutes.' },
});

// Apply
app.use('/api', globalLimit);
app.use('/api/auth/login', authLimit);
app.use('/api/auth/register', authLimit);
```

**Behind a proxy (Nginx, load balancer):**
```ts
app.set('trust proxy', 1); // trust first proxy
// Or: app.set('trust proxy', 'loopback, 10.0.0.0/8');
```

**For production scale:** Use Redis as the store:
```ts
import { RedisStore } from 'rate-limit-redis';
// Pass: store: new RedisStore({ client: redisClient })
```

## JWT Authentication Pattern

### Token generation
```ts
import jwt from 'jsonwebtoken';

export function generateTokens(userId: string) {
  const accessToken = jwt.sign({ sub: userId }, config.JWT_SECRET, { expiresIn: '15m' });
  const refreshToken = jwt.sign({ sub: userId }, config.JWT_REFRESH_SECRET, { expiresIn: '7d' });
  return { accessToken, refreshToken };
}
```

### Login endpoint
```ts
router.post('/auth/login', authLimit, async (req, res) => {
  const { email, password } = req.body;
  const user = await userService.verifyCredentials(email, password);
  const { accessToken, refreshToken } = generateTokens(user.id);

  // Refresh token in HttpOnly cookie — not accessible to JS
  res.cookie('refreshToken', refreshToken, {
    httpOnly: true,
    secure: config.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: 7 * 24 * 60 * 60 * 1000, // 7d in ms
  });

  res.json({ accessToken, user: { id: user.id, email: user.email } });
});
```

### Auth middleware
```ts
export const authenticate: RequestHandler = (req, res, next) => {
  const token = req.headers.authorization?.replace('Bearer ', '');
  if (!token) throw new UnauthorizedError();
  try {
    const payload = jwt.verify(token, config.JWT_SECRET) as { sub: string };
    req.userId = payload.sub;
    next();
  } catch {
    throw new UnauthorizedError();
  }
};
```

**Rules:**
- Access token in `Authorization: Bearer <token>` header (memory only, never localStorage)
- Refresh token in `HttpOnly; Secure; SameSite=Strict` cookie
- Rotate refresh tokens on every use (detect theft via reuse detection)

## Node.js Streaming Patterns

### Stream a file to the client
```ts
import { createReadStream } from 'fs';

router.get('/download/:filename', authenticate, (req, res) => {
  const filePath = path.resolve('./uploads', req.params.filename);
  // Security: ensure path doesn't escape uploads dir
  if (!filePath.startsWith(path.resolve('./uploads'))) {
    return res.status(403).json({ error: 'Access denied' });
  }

  res.setHeader('Content-Type', 'application/octet-stream');
  res.setHeader('Content-Disposition', `attachment; filename="${req.params.filename}"`);

  const stream = createReadStream(filePath);
  stream.on('error', () => res.status(404).end());
  stream.pipe(res);
});
```

### Stream CSV processing
```ts
import { createReadStream } from 'fs';
import { parse } from 'csv-parse';
import { pipeline } from 'stream/promises';

async function processCsv(filePath: string) {
  const results: Record<string, string>[] = [];
  await pipeline(
    createReadStream(filePath),
    parse({ columns: true, skip_empty_lines: true }),
    async function* (source) {
      for await (const row of source) {
        results.push(row); // or write to DB in batches
      }
    }
  );
  return results;
}
```

### SSE (Server-Sent Events) — real-time updates
```ts
router.get('/events', (req, res) => {
  res.setHeader('Content-Type', 'text/event-stream');
  res.setHeader('Cache-Control', 'no-cache');
  res.setHeader('Connection', 'keep-alive');
  res.flushHeaders();

  const interval = setInterval(() => {
    res.write(`data: ${JSON.stringify({ time: Date.now() })}\n\n`);
  }, 1000);

  req.on('close', () => clearInterval(interval));
});
```

## Health Check Endpoints

```ts
// Liveness — is the process alive? (restart if fails)
app.get('/health', (req, res) => {
  res.json({ status: 'ok', uptime: process.uptime(), timestamp: Date.now() });
});

// Readiness — can it serve traffic? (remove from load balancer if fails)
app.get('/ready', async (req, res) => {
  const checks: Record<string, boolean> = {};

  // DB check
  try {
    await db.$queryRaw`SELECT 1`;
    checks.database = true;
  } catch {
    checks.database = false;
  }

  // Redis check
  try {
    await redis.ping();
    checks.redis = true;
  } catch {
    checks.redis = false;
  }

  const ready = Object.values(checks).every(Boolean);
  res.status(ready ? 200 : 503).json({
    status: ready ? 'ready' : 'not ready',
    checks,
  });
});
```

